// Memoized component
import React from 'react';

const sumOfSquares = (n) => {
  const squares = [...Array(n + 1).keys()]
    .map((i) => i ** 2);
  return React.memo(() => squares.reduce((a, b) => a + b, 0));
};

const App = () => {
  const [n, setN] = React.useState(5);
  return (
    <div>
      <h1>Sum of squares: {sumOfSquares(n)(n)}</h1>
      <button onClick={() => setN(n + 1)}>Increase n</button>
    </div>
  );
};

export default App;

