// Memoized component
class SumOfSquares:
    def __init__(self):
        self.n = 5

    def calculate(self):
        squares = [i ** 2 for i in range(self.n + 1)]
        return sum(squares)

    def render(self):
        return React.memo(self.calculate)

class App:
    def __init__(self):
        self.state = {'n': 5}

    def increase_n(self):
        self.state['n'] += 1

    def render(self):
        return (
            <div>
                <h1>Sum of squares: {self.render().calculate()}</h1>
                <button onClick={self.increase_n}>Increase n</button>
            </div>
        )

